// ============================================================================
// Core sequences
// ============================================================================

/** Fibonacci sequence. */
export function fib(n: number): bigint {
  if (n <= 0) return 0n;
  if (n === 1) return 1n;
  let a = 0n;
  let b = 1n;
  for (let i = 2; i <= n; i++) {
    [a, b] = [b, a + b];
  }
  return b;
}

/** Lucas sequence: L(0)=2, L(1)=1, L(n+2)=L(n+1)+L(n). */
export function lucas(n: number): bigint {
  if (n === 0) return 2n;
  if (n === 1) return 1n;
  let a = 2n;
  let b = 1n;
  for (let i = 2; i <= n; i++) {
    [a, b] = [b, a + b];
  }
  return b;
}

// ============================================================================
// GnosticIndex — strict typed enum mirroring the Lean inductive type
// ============================================================================

/**
 * The named Gnostic indices. Each maps to a position in Fibonacci space.
 * The Lucas value at that position is the observable (trace) counterpart.
 */
export enum GnosticIndex {
  Barbelo = 'barbelo',
  Syzygy = 'syzygy',
  Proton = 'proton',
  Primitives = 'primitives',
  Emanations = 'emanations',
  Sophia = 'sophia',
  Kenoma = 'kenoma',
  Void = 'void',
  Pleroma = 'pleroma',
}

/** Fibonacci-space position for each Gnostic index. */
export function fibIndex(g: GnosticIndex): number {
  switch (g) {
    case GnosticIndex.Barbelo:    return 1;
    case GnosticIndex.Syzygy:     return 3;
    case GnosticIndex.Proton:     return 4;
    case GnosticIndex.Primitives: return 5;
    case GnosticIndex.Emanations: return 6;
    case GnosticIndex.Sophia:     return 9;
    case GnosticIndex.Kenoma:     return 10;
    case GnosticIndex.Void:       return 8;
    case GnosticIndex.Pleroma:    return 10;
  }
}

/** The named Gnostic number (the classical value). */
export function gnosticValue(g: GnosticIndex): bigint {
  switch (g) {
    case GnosticIndex.Barbelo:    return 1n;
    case GnosticIndex.Syzygy:     return 2n;
    case GnosticIndex.Proton:     return 3n;
    case GnosticIndex.Primitives: return 5n;
    case GnosticIndex.Emanations: return 6n;
    case GnosticIndex.Sophia:     return 9n;
    case GnosticIndex.Kenoma:     return 10n;
    case GnosticIndex.Void:       return 21n;
    case GnosticIndex.Pleroma:    return 55n;
  }
}

/** Fibonacci value at the Gnostic index. */
export function fibValue(g: GnosticIndex): bigint {
  return fib(fibIndex(g));
}

/** Lucas value (trace/observable) at the Gnostic index. */
export function lucasValue(g: GnosticIndex): bigint {
  return lucas(fibIndex(g));
}

// ============================================================================
// Mechanized verification (runtime assertions mirroring Lean proofs)
// ============================================================================

/** GnosticIndex record with all computed fields. */
export interface GnosticRecord {
  readonly name: GnosticIndex;
  readonly fibIdx: number;
  readonly fibVal: bigint;
  readonly lucasVal: bigint;
  readonly gnosticVal: bigint;
  readonly flankingPast: bigint;   // F(n-1)
  readonly flankingFuture: bigint; // F(n+1)
  readonly isSelfDual: boolean;    // L(n) === F(n)
}

/** Compute the full record for a Gnostic index. */
export function computeGnosticRecord(g: GnosticIndex): GnosticRecord {
  const idx = fibIndex(g);
  const fVal = fibValue(g);
  const lVal = lucasValue(g);
  const gVal = gnosticValue(g);
  const past = fib(idx - 1);
  const future = fib(idx + 1);

  return {
    name: g,
    fibIdx: idx,
    fibVal: fVal,
    lucasVal: lVal,
    gnosticVal: gVal,
    flankingPast: past,
    flankingFuture: future,
    isSelfDual: lVal === fVal,
  };
}

/** All Gnostic indices. */
export const ALL_GNOSTIC_INDICES: readonly GnosticIndex[] = [
  GnosticIndex.Barbelo,
  GnosticIndex.Syzygy,
  GnosticIndex.Proton,
  GnosticIndex.Primitives,
  GnosticIndex.Emanations,
  GnosticIndex.Sophia,
  GnosticIndex.Kenoma,
  GnosticIndex.Void,
  GnosticIndex.Pleroma,
] as const;

/**
 * THM-FLANKING-GNOSTIC (runtime verification):
 * Verify that L(n) = F(n-1) + F(n+1) at every Gnostic index.
 * Throws if any index violates the flanking identity.
 */
export function verifyFlankingIdentity(): void {
  for (const g of ALL_GNOSTIC_INDICES) {
    const rec = computeGnosticRecord(g);
    const expected = rec.flankingPast + rec.flankingFuture;
    if (rec.lucasVal !== expected) {
      throw new Error(
        `Flanking identity violated at ${rec.name}: ` +
        `L(${rec.fibIdx})=${rec.lucasVal} ≠ F(${rec.fibIdx - 1})+F(${rec.fibIdx + 1})=${expected}`
      );
    }
  }
}

/**
 * THM-BRIDGE-IDENTITY (runtime verification):
 * Verify that L(n) + F(n) = 2·F(n+1) at every Gnostic index.
 */
export function verifyBridgeIdentity(): void {
  for (const g of ALL_GNOSTIC_INDICES) {
    const rec = computeGnosticRecord(g);
    const lhs = rec.lucasVal + rec.fibVal;
    const rhs = 2n * fib(rec.fibIdx + 1);
    if (lhs !== rhs) {
      throw new Error(
        `Bridge identity violated at ${rec.name}: ` +
        `L(${rec.fibIdx})+F(${rec.fibIdx})=${lhs} ≠ 2·F(${rec.fibIdx + 1})=${rhs}`
      );
    }
  }
}

/**
 * THM-SELF-DUAL-BARBELO (runtime verification):
 * Verify that Barbelo is the only self-dual Gnostic index.
 */
export function verifySelfDualBarbelo(): void {
  for (const g of ALL_GNOSTIC_INDICES) {
    const rec = computeGnosticRecord(g);
    if (g === GnosticIndex.Barbelo) {
      if (!rec.isSelfDual) {
        throw new Error('Barbelo must be self-dual: L(1) should equal F(1)');
      }
    } else {
      if (rec.isSelfDual) {
        throw new Error(`Only Barbelo is self-dual, but ${rec.name} also has L=F`);
      }
    }
  }
}

// ============================================================================
// Picolorenzo intervals (Lucas-valued)
