/** Lucas picolorenzo interval in microdays. */
export function lucasPlo(g: GnosticIndex): bigint {
  return lucasValue(g) * PICOLORENZO;
}

/** Fibonacci picolorenzo interval in microdays (from GnosticTime). */
export function fibPlo(g: GnosticIndex): bigint {
  return gnosticValue(g) * PICOLORENZO;
}

/**
 * The Lucas Pleroma coincidence: L(10) × π ≈ 386.4 days.
 * The excess over 365 days is ≈ 21.4, close to F(8) = 21 = Void.
 */
export function lucasPleromaSolarExcess(): {
  lucasDays: number;
  excessDays: number;
  excessNearVoid: boolean;
} {
  const lucasMicrodays = lucasPlo(GnosticIndex.Pleroma);
  const lucasDays = Number(lucasMicrodays) / 1_000_000;
  const excessDays = lucasDays - 365;
  return {
    lucasDays,
    excessDays,
    excessNearVoid: Math.abs(excessDays - 21) < 1.5,
  };
}

// ============================================================================
// Pisot Coordinates — (n, F(n), L(n)) as a point in 3-space
// ============================================================================

/**
 * A Pisot coordinate is a triple (index, hidden, observable) where:
 *   - idx: position in Fibonacci space (chronological time)
 *   - hidden: F(n), the antisymmetric eigenvalue projection
 *   - observable: L(n), the symmetric trace projection
 *
 * The triple is constrained by the flanking identity:
 *   observable = F(idx-1) + F(idx+1)
 *
 * And the discriminant identity:
 *   observable² − 5·hidden² = 4·(−1)^idx
 *
 * Asymptotically, observable/hidden → √5 = √Δ where Δ=5 is the
 * discriminant of the golden polynomial x²−x−1=0.
 */
export interface PisotCoord {
  readonly idx: number;        // Fibonacci-space index (time)
  readonly hidden: bigint;     // F(n): hidden state
  readonly observable: bigint; // L(n): trace / observable state
}

/** Construct a PisotCoord from a Fibonacci index. */
export function pisotCoordOfIndex(n: number): PisotCoord {
  return { idx: n, hidden: fib(n), observable: lucas(n) };
}

/** Construct a PisotCoord from a GnosticIndex. */
export function pisotCoordOfGnostic(g: GnosticIndex): PisotCoord {
  return pisotCoordOfIndex(fibIndex(g));
}

/** All Pisot coordinates at Gnostic indices. */
export function allPisotCoords(): readonly PisotCoord[] {
  return ALL_GNOSTIC_INDICES.map(pisotCoordOfGnostic);
}

// ============================================================================
// Discriminant identity: L(n)² − 5·F(n)² = 4·(−1)^n
// ============================================================================

/**
 * The discriminant of the golden polynomial x²−x−1 is Δ = 5.
 * This is the fundamental algebraic constant governing the Pisot system.
 *
 * The identity L(n)² − 5·F(n)² = 4·(−1)^n means:
 * - Even n: L² = 5F² + 4  (observable overshoots)
 * - Odd n:  L² = 5F² − 4  (observable undershoots)
 *
 * Dividing by F²: (L/F)² = 5 ± 4/F²  →  L/F → √5 = √Δ
 */
export const GOLDEN_DISCRIMINANT = 5n;

/**
 * Compute the discriminant residual: L(n)² − 5·F(n)².
 * Should always equal +4 (even n) or -4 (odd n).
 */
export function discriminant(coord: PisotCoord): bigint {
  return coord.observable ** 2n - GOLDEN_DISCRIMINANT * coord.hidden ** 2n;
}

/**
 * THM-DISCRIMINANT (runtime verification):
 * Verify that L(n)² − 5·F(n)² = ±4 at every Gnostic index.
 */
export function verifyDiscriminant(): void {
  for (const g of ALL_GNOSTIC_INDICES) {
    const coord = pisotCoordOfGnostic(g);
    const d = discriminant(coord);
    const expected = coord.idx % 2 === 0 ? 4n : -4n;
    if (d !== expected) {
      throw new Error(
        `Discriminant violated at ${g}: ` +
        `L(${coord.idx})²−5·F(${coord.idx})² = ${d}, expected ${expected}`
      );
    }
  }
}

// ============================================================================
// Observable-to-hidden ratio convergence → √Δ = √5
// ============================================================================

/**
 * Compute L(n)/F(n) as a floating-point ratio.
 * Converges to √5 ≈ 2.2360679... with oscillating sign.
 *
 * From Binet's formulas:
 *   L(n)/F(n) = √5 · (φⁿ + ψⁿ)/(φⁿ − ψⁿ)
 * Since |ψ| < 1, ψⁿ → 0, so L/F → √5.
 *
 * The number 5 is the discriminant of x²−x−1=0.
 * Observable reality is hidden reality scaled by √Δ.
 */
export function observableToHiddenRatio(n: number): number {
  const f = fib(n);
  const l = lucas(n);
  if (f === 0n) return Infinity;
  // Use high-precision integer arithmetic: L*10^15 / F, then divide
  const precision = 1_000_000_000_000_000n;
  const ratio = (l * precision) / f;
  return Number(ratio) / Number(precision);
}

/**
 * THM-RATIO-CONVERGENCE (runtime verification):
 * Verify that L(n)/F(n) converges toward √5 with decreasing error.
 */
export function verifyRatioConvergence(): void {
  const sqrt5 = Math.sqrt(5);
  let prevError = Infinity;
  // Check indices 3 through 20
  for (let n = 3; n <= 20; n++) {
    const ratio = observableToHiddenRatio(n);
    const error = Math.abs(ratio - sqrt5);
    if (n > 5 && error >= prevError) {
      throw new Error(
        `Ratio convergence violated: error at n=${n} (${error}) ` +
        `>= error at n=${n - 1} (${prevError})`
      );
    }
    prevError = error;
  }
}

