/**
 * mitosis: Spawns a new daughter cell from the preserved DNA and mother fork.
 * - Restores the Pisot geometric manifold deterministically.
 * - Injects the irrational Weyl step to shatter resonance.
 */
export function mitosis(mother: ImmuneExecutionFork, dna: CausalDNA): ImmuneExecutionFork {
  const h_next = dna.h_prev + dna.h_curr; // F(n+1)
  const o_next = 2n * dna.h_curr + h_next; // L(n+1) = 2F_n + F_{n+1}
  
  const daughterPisot: PisotCoord = {
    idx: mother.pisot.idx + 1,
    hidden: h_next,
    observable: o_next,
  };

  return {
    pisot: daughterPisot,
    weylPhase: (mother.weylPhase + GOLDEN_VENT) % 1.0,
  };
}

